import{_ as i,o as a,c as e,a0 as r}from"./chunks/framework.DE0haUFQ.js";const k=JSON.parse('{"title":"LLM Wiki v3 知识编译系统","description":"基于 Karpathy LLM Wiki + 三步编译法改进的知识管理系统，从 Runtime RAG 升级到 Compile-time Wiki","frontmatter":{"type":"Concept","title":"LLM Wiki v3 知识编译系统","description":"基于 Karpathy LLM Wiki + 三步编译法改进的知识管理系统，从 Runtime RAG 升级到 Compile-time Wiki","source_url":"n/a","source_title":"LLM Wiki 3.0 AGENTS.md","source_platform":"内部","ingest_date":"2026-07-12T00:00:00.000Z","access_date":"2026-07-12T00:00:00.000Z","tags":["知识管理","PKMS","LLMWiki","方法论"],"status":"compiled","review_count":0,"last_review":"2026-07-12T00:00:00.000Z","next_review":"2026-07-13T00:00:00.000Z"},"headers":[],"relativePath":"wiki/concepts/LLMWikiV3.md","filePath":"wiki/concepts/LLMWikiV3.md"}'),d={name:"wiki/concepts/LLMWikiV3.md"};function l(o,t,n,h,s,c){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="llm-wiki-v3-知识编译系统" tabindex="-1">LLM Wiki v3 知识编译系统 <a class="header-anchor" href="#llm-wiki-v3-知识编译系统" aria-label="Permalink to &quot;LLM Wiki v3 知识编译系统&quot;">​</a></h1><h2 id="系统定位" tabindex="-1">系统定位 <a class="header-anchor" href="#系统定位" aria-label="Permalink to &quot;系统定位&quot;">​</a></h2><p><strong>知识编译系统</strong> —— 不是简单的文件存储，而是让 LLM 持续编译、维护、进化知识资产。</p><p>核心升级：从 Runtime RAG（提问时才检索）→ Compile-time Wiki（知识在编译时已被处理）。</p><h2 id="三步编译法" tabindex="-1">三步编译法 <a class="header-anchor" href="#三步编译法" aria-label="Permalink to &quot;三步编译法&quot;">​</a></h2><h3 id="第一步-浓缩" tabindex="-1">第一步：浓缩 <a class="header-anchor" href="#第一步-浓缩" aria-label="Permalink to &quot;第一步：浓缩&quot;">​</a></h3><p>用剃刀法则：删掉这条信息会影响理解吗？不会就删。 输出：核心结论（不超过 3 条）+ 支撑每条结论的关键证据。</p><h3 id="第二步-质疑" tabindex="-1">第二步：质疑 <a class="header-anchor" href="#第二步-质疑" aria-label="Permalink to &quot;第二步：质疑&quot;">​</a></h3><p>针对每条核心结论：</p><ol><li>依赖哪些前提假设？</li><li>如果前提不成立，结论还成立吗？</li><li>数据来源可靠吗？</li><li>有没有反例或边界条件？</li></ol><h3 id="第三步-对标" tabindex="-1">第三步：对标 <a class="header-anchor" href="#第三步-对标" aria-label="Permalink to &quot;第三步：对标&quot;">​</a></h3><ol><li>其他领域有没有类似现象？</li><li>可以迁移到哪些场景？</li><li>跨域关联 → 创建/更新概念条目</li></ol><h2 id="编译模式" tabindex="-1">编译模式 <a class="header-anchor" href="#编译模式" aria-label="Permalink to &quot;编译模式&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式</th><th>触发条件</th><th>动作</th></tr></thead><tbody><tr><td>加入 Wiki</td><td>&quot;编译这篇文章&quot; / &quot;加入 Wiki&quot;</td><td>完整编译流程</td></tr><tr><td>加入待办</td><td>&quot;记个待办&quot; / &quot;待后续查阅&quot;</td><td>轻量记录到待办清单</td></tr><tr><td>AI 主动识别</td><td>编译中发现需亲自尝试</td><td>主动询问是否记待办</td></tr><tr><td>问询触发</td><td>概念解释类问答</td><td>生成轻量概念页</td></tr></tbody></table><h2 id="标签体系" tabindex="-1">标签体系 <a class="header-anchor" href="#标签体系" aria-label="Permalink to &quot;标签体系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>标签</th><th>含义</th><th>示例</th></tr></thead><tbody><tr><td>#工作-华为</td><td>华为工作场景相关</td><td>财经湖调度、数据治理口径</td></tr><tr><td>#数据治理</td><td>专业领域</td><td>血缘追踪、元数据管理</td></tr><tr><td>#AI应用</td><td>AI+数据交叉</td><td>ChatBI Agent、Semantic Weaver</td></tr><tr><td>#工具</td><td>具体工具</td><td>DuckDB、dbt、DataHub</td></tr><tr><td>#vibecoding</td><td>个人项目方向</td><td>side project、创意编程</td></tr><tr><td>#方法论</td><td>通用方法</td><td>三步编译法、PARA</td></tr></tbody></table><h2 id="质量检查清单-强制" tabindex="-1">质量检查清单（强制） <a class="header-anchor" href="#质量检查清单-强制" aria-label="Permalink to &quot;质量检查清单（强制）&quot;">​</a></h2><ul><li>[ ] frontmatter 字段正确（date=编译日期，source/author/url正确）</li><li>[ ] 概念文件核对（提取N个 = 生成N个）</li><li>[ ] 索引统计正确（Total数字与实际一致）</li><li>[ ] 日志一致性（描述与实际操作一致）</li><li>[ ] 原文与资产完整性</li></ul><h2 id="健康检查-每周" tabindex="-1">健康检查（每周） <a class="header-anchor" href="#健康检查-每周" aria-label="Permalink to &quot;健康检查（每周）&quot;">​</a></h2><ol><li><strong>一致性检查</strong>：同一个概念在不同条目中的定义是否一致</li><li><strong>完整性检查</strong>：每个概念条目是否包含所有必填字段</li><li><strong>孤岛检测</strong>：找出入链和出链都少于 2 的页面</li><li><strong>跨目录一致性</strong>：扫描风格规则有无遗漏或冲突</li></ol><h1 id="citations" tabindex="-1">Citations <a class="header-anchor" href="#citations" aria-label="Permalink to &quot;Citations&quot;">​</a></h1><ul><li>来源: 第二大脑 / 0-Wiki/AGENTS.md</li><li>灵感: Karpathy LLM Wiki + 饼干哥哥三步编译法</li></ul>',22)])])}const m=i(d,[["render",l]]);export{k as __pageData,m as default};
